export function searchCuratedGrounds(query, limit) {
  var q = String(query || "")
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, " ")
    .trim();
  if (q.length < 2) return [];
  var terms = q.split(/\s+/).filter(Boolean);
  var out = [];

  WA_GROUNDS.forEach(function (g) {
    var hay = [g.name, g.suburb, (g.aliases || []).join(" ")].join(" ").toLowerCase();
    var score = 0;
    var all = terms.every(function (t) {
      return hay.indexOf(t) >= 0;
    });
    if (!all) return;
    terms.forEach(function (t) {
      if (g.name.toLowerCase().indexOf(t) === 0) score += 40;
      else if (g.name.toLowerCase().indexOf(t) >= 0) score += 25;
      if (g.suburb.toLowerCase().indexOf(t) >= 0) score += 15;
    });
    if (g.name.toLowerCase().indexOf(q) >= 0) score += 30;
    score += 80;
    out.push({
      name: g.name,
      latitude: g.lat,
      longitude: g.lng,
      admin1: "Western Australia",
      admin2: g.suburb,
      country_code: "AU",
      source: "curated",
      score: score,
    });
  });

  out.sort(function (a, b) {
    return b.score - a.score;
  });
  return out.slice(0, limit || 15);
}
